async function loadSignalQuality() {
  const body    = document.getElementById('sq-body');
  const summary = document.getElementById('sq-summary');
  try {
    const d = await apiFetch('/api/signal-quality');
    if (!d.available) {
      body.innerHTML = '<div class="empty">No signal quality data yet — run <code>pull signal-quality-scan</code>.</div>';
      summary.textContent = '';
      return;
    }
    const scores  = d.scores ?? {};
    const lowList = (d.low_quality_modules ?? []);
    summary.textContent = `${d.date ?? ''} · ${d.modules_scored ?? 0} modules · ${lowList.length} low quality`;

    const entries = Object.entries(scores).sort(([, a], [, b]) => b.composite_score - a.composite_score);
    if (!entries.length) {
      body.innerHTML = '<div class="empty">No module scores computed.</div>';
      return;
    }

    const rows = entries.map(([id, s]) => {
      const pct   = Math.round((s.composite_score ?? 0) * 100);
      const cls   = pct >= 60 ? 'green' : pct >= 30 ? 'yellow' : 'red';
      const badge = s.low_quality ? '🔴 low' : pct >= 60 ? '✅' : '⚠️';
      return `<div class="sq-row">
        <span class="sq-label" title="Hit ${Math.round(s.hit_rate*100)}% · Noise ${Math.round(s.noise_rate*100)}% · Rel ${Math.round(s.reliability_score*100)}% · Fresh ${Math.round(s.freshness_score*100)}%">${esc(id)}</span>
        <div class="sq-bar-wrap"><div class="sq-bar ${cls}" style="width:${pct}%"></div></div>
        <span class="sq-pct">${pct}%</span>
        <span class="sq-badge">${badge}</span>
      </div>`;
    }).join('');

    body.innerHTML = `<div class="sq-grid">${rows}</div>
      <div style="font-size:10px;color:var(--text-muted);margin-top:8px">
        Composite = hit×0.4 + (1−noise)×0.3 + reliability×0.2 + freshness×0.1 · hover module for detail
        ${lowList.length ? `<br>Low-quality modules capped at 2 signals in daily report: <strong>${lowList.join(', ')}</strong>` : ''}
      </div>`;
  } catch (e) {
    body.innerHTML = `<div class="empty">Error: ${esc(e.message)}</div>`;
  }
}

